/**
 * Generate Streak firewall config.
 *
 * Data source: https://streak.readme.io/reference/authentication
 *
 * Streak uses HTTP Basic Auth with the API key as the username and an empty password.
 * Token format: 32-character hex string.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://streak.readme.io/docs/authentication";
// Streak API key format is undocumented; use generic base62 placeholder
const PLACEHOLDER_VALUE = "Coffee5afe10ca1Coffee5afe10ca1Coffee5afe10";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Streak API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:streak",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const streakFirewall = {",
    '  name: "streak",',
    '  description: "Streak CRM API",',
    "  placeholders: {",
    `    STREAK_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.streak.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "${{ basic(secrets.STREAK_TOKEN, ) }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Streak firewall config...");
  const ts = generateTypeScript();
  writeOutput("streak", ts, import.meta.dirname);
}
